var getAllRequests = async (userId) => {
  const result = await prisma.rentalRequest.findMany({
    where: {
      property: {
        landlordId: userId
      }
    },
    include: {
      property: true,
      user: {
        select: {
          id: true,
          name: true,
          email: true
        }
      }
    }
  });
  return result;
};
var updateRequestStatus = async (userId, requestId, status) => {
  const request = await prisma.rentalRequest.findUniqueOrThrow({
    where: {
      id: requestId
    }
  });
  const property = await prisma.property.findUniqueOrThrow({
    where: {
      id: request.propertyId
    }
  });
  if (property.landlordId !== userId) {
    throw new Error("You are not authorized to update this request");
  }
  const result = await prisma.$transaction(async (tx) => {
    const updatedRequest = await tx.rentalRequest.update({
      where: { id: requestId },
      data: { approveStatus: status }
    });
    if (status === "APPROVED") {
      await tx.property.update({
        where: { id: request.propertyId },
        data: { isAvailable: false }
      });
    }
    return updatedRequest;
  });
  return result;
};
