// src/middlewares/globalErrorHandler.ts
import httpStatus4 from "http-status";
import jwt2 from "jsonwebtoken";
import Stripe from "stripe";
var { JsonWebTokenError, TokenExpiredError } = jwt2;
var globalErrorHandler = (err, req, res, next) => {
  let statusCode = err.statusCode || httpStatus4.INTERNAL_SERVER_ERROR;
  let errorMessage = err.message || "Internal Server Error";
  let errorName = err.name || "Internal Server Error";
  if (err instanceof prismaNamespace_exports.PrismaClientValidationError) {
    statusCode = httpStatus4.BAD_REQUEST;
    errorMessage = "You have provided incorrect fields type or missing fields";
  } else if (err instanceof prismaNamespace_exports.PrismaClientKnownRequestError) {
    if (err.code === "P2002") {
      const field = err.meta?.target?.join(", ") || "field";
      statusCode = httpStatus4.CONFLICT;
      errorMessage = `Duplicate value found for unique field: ${field}`;
    } else if (err.code === "P2003") {
      statusCode = httpStatus4.BAD_REQUEST;
      errorMessage = "Foreign key constraint failed";
    } else if (err.code === "P2025") {
      statusCode = httpStatus4.NOT_FOUND;
      errorMessage = "Record not found";
    } else if (err.code === "P2014") {
      statusCode = httpStatus4.BAD_REQUEST;
      errorMessage = "Required relation violation";
    }
  } else if (err instanceof prismaNamespace_exports.PrismaClientInitializationError) {
    statusCode = httpStatus4.INTERNAL_SERVER_ERROR;
    errorMessage = "Database connection failed";
  } else if (err instanceof prismaNamespace_exports.PrismaClientUnknownRequestError) {
    statusCode = httpStatus4.INTERNAL_SERVER_ERROR;
    errorMessage = "Unknown database error";
  } else if (err instanceof JsonWebTokenError) {
    statusCode = httpStatus4.UNAUTHORIZED;
    errorMessage = "Invalid token";
  } else if (err instanceof TokenExpiredError) {
    statusCode = httpStatus4.UNAUTHORIZED;
    errorMessage = "Token has expired";
  } else if (err instanceof Stripe.errors.StripeError) {
    statusCode = httpStatus4.BAD_REQUEST;
    errorMessage = err.message;
  } else if (err instanceof SyntaxError && "body" in err) {
    statusCode = httpStatus4.BAD_REQUEST;
    errorMessage = "Malformed JSON in request body";
  } else if (err.statusCode) {
    statusCode = err.statusCode;
  }
  res.status(statusCode).json({
    success: false,
    statusCode,
    name: errorName,
    message: errorMessage,
    ...process.env.NODE_ENV === "development" && { error: err.stack }
  });
};

